     1→import type {
     2→  PaneInfo,
     3→  TerminalController,
     4→} from './terminal-controller.interface.ts';
     5→
     6→/** MVP 最大 pane 數量（安全上限，Phase 2 可設定） */
     7→const MAX_PANES = 6;
     8→
     9→/** Pane title description 最大長度 */
    10→const MAX_DESCRIPTION_LENGTH = 50;
    11→
    12→/**
    13→ * 清理並格式化 pane title
    14→ * - 移除 control characters 和 tmux # 特殊序列
    15→ * - 截斷超長描述
    16→ */
    17→function sanitizePaneTitle(description: string): string {
    18→  return (
    19→    description
    20→      // eslint-disable-next-line no-control-regex
    21→      .replace(/[\x00-\x1f\x7f]/g, ' ') // control chars -> space
    22→      .replace(/#/g, '') // tmux interprets #() sequences
    23→      .trim()
    24→      .slice(0, MAX_DESCRIPTION_LENGTH)
    25→  );
    26→}
    27→
    28→/** applyLayout debounce 延遲（ms） */
    29→const LAYOUT_DEBOUNCE_MS = 50;
    30→
    31→/**
    32→ * Pane 生命週期管理器
    33→ *
    34→ * 負責追蹤所有開啟的 pane，並在需要時統一清理。
    35→ * 是 pane 狀態的唯一 source of truth。
    36→ */
    37→export class PaneManager {
    38→  private controller: TerminalController;
    39→  private commandBuilder: (agentId: string, subagentPath: string) => string;
    40→  private panes: Map<string, PaneInfo> = new Map(); // agentId -> PaneInfo
    41→  /** 正在開啟中的 agentId（防止併發超開） */
    42→  private pendingAgentIds: Set<string> = new Set();
    43→  /** 待關閉的 agentId（pane 還在 pending 時就收到 done 事件） */
    44→  private pendingCloseAgentIds: Set<string> = new Set();
    45→  /** applyLayout debounce timer */
    46→  private layoutTimer: ReturnType<typeof setTimeout> | null = null;
    47→
    48→  constructor(
    49→    controller: TerminalController,
    50→    commandBuilder: (agentId: string, subagentPath: string) => string
    51→  ) {
    52→    this.controller = controller;
    53→    this.commandBuilder = commandBuilder;
    54→  }
    55→
    56→  /**
    57→   * 為 subagent 開啟新 pane
    58→   * - 已存在相同 agentId 的 pane 時跳過（去重）
    59→   * - 超過 MAX_PANES 時跳過（安全上限）
    60→   * - 使用 pendingAgentIds 防止併發呼叫超開
    61→   * - description 用於命名 pane（可選，來自 Task tool_use 的 description 欄位）
    62→   */
    63→  async openPane(
    64→    agentId: string,
    65→    subagentPath: string,
    66→    description?: string
    67→  ): Promise<void> {
    68→    if (this.panes.has(agentId)) return;
    69→    if (this.pendingAgentIds.has(agentId)) return;
    70→    if (this.panes.size + this.pendingAgentIds.size >= MAX_PANES) return;
    71→
    72→    this.pendingAgentIds.add(agentId);
    73→    try {
    74→      const cmd = this.commandBuilder(agentId, subagentPath);
    75→      const pane = await this.controller.createPane(cmd, agentId);
    76→      if (pane) {
    77→        this.panes.set(agentId, pane);
    78→
    79→        // Best-effort pane naming (before pendingClose check)
    80→        if (description && this.controller.renamePane) {
    81→          const title = sanitizePaneTitle(description);
    82→          try {
    83→            await this.controller.renamePane(pane.id, title);
    84→          } catch {
    85→            // 命名失敗不影響 pane 功能
    86→          }
    87→        }
    88→
    89→        // 排程佈局更新（debounce，連續開多個 pane 時只觸發一次）
    90→        this.scheduleLayout();
    91→
    92→        // 檢查是否在 pending 期間收到了 done 事件
    93→        if (this.pendingCloseAgentIds.has(agentId)) {
    94→          this.pendingCloseAgentIds.delete(agentId);
    95→          // 立刻關閉這個 pane
    96→          await this.closePaneByAgentId(agentId);
    97→        }
    98→      } else {
    99→        // createPane 失敗，清除待關閉狀態（沒有 pane 就不需要關閉）
   100→        this.pendingCloseAgentIds.delete(agentId);
   101→      }
   102→    } catch {
   103→      // 非預期錯誤（如 commandBuilder throw），清理所有相關狀態
   104→      this.pendingCloseAgentIds.delete(agentId);
   105→    } finally {
   106→      this.pendingAgentIds.delete(agentId);
   107→    }
   108→  }
   109→
   110→  /**
   111→   * 關閉所有已追蹤的 pane（best-effort）
   112→   */
   113→  async closeAll(): Promise<void> {
   114→    this.clearLayoutTimer();
   115→    const closePromises = [...this.panes.values()].map((p) =>
   116→      this.controller.closePane(p.id).catch(() => {})
   117→    );
   118→    await Promise.all(closePromises);
   119→    this.panes.clear();
   120→    this.pendingCloseAgentIds.clear();
   121→  }
   122→
   123→  /**
   124→   * 排程佈局更新（debounce）
   125→   * 連續開多個 pane 時只在最後觸發一次 tmux select-layout
   126→   */
   127→  private scheduleLayout(): void {
   128→    this.clearLayoutTimer();
   129→    this.layoutTimer = setTimeout(() => {
   130→      this.layoutTimer = null;
   131→      this.applyLayout().catch(() => {});
   132→    }, LAYOUT_DEBOUNCE_MS);
   133→  }
   134→
   135→  private clearLayoutTimer(): void {
   136→    if (this.layoutTimer) {
   137→      clearTimeout(this.layoutTimer);
   138→      this.layoutTimer = null;
   139→    }
   140→  }
   141→
   142→  /**
   143→   * 套用佈局（如果 controller 支援）
   144→   * Best-effort 操作，失敗不影響核心功能
   145→   */
   146→  private async applyLayout(): Promise<void> {
   147→    if (this.controller.applyLayout) {
   148→      try {
   149→        await this.controller.applyLayout('main-vertical');
   150→      } catch {
   151→        // 靜默忽略佈局失敗
   152→      }
   153→    }
   154→  }
   155→
   156→  /**
   157→   * 根據 agentId 關閉對應的 pane
   158→   * Best-effort 操作，失敗不影響核心功能
   159→   * 如果 pane 還在 pending，會標記為待關閉，等 pane 建立後自動關閉
   160→   */
   161→  async closePaneByAgentId(agentId: string): Promise<void> {
   162→    // 如果 pane 還在開啟中，標記為待關閉
   163→    if (this.pendingAgentIds.has(agentId) && !this.panes.has(agentId)) {
   164→      this.pendingCloseAgentIds.add(agentId);
   165→      return;
   166→    }
   167→
   168→    const pane = this.panes.get(agentId);
   169→    if (!pane) return;
   170→
   171→    // 立刻移除，防止並行呼叫重複觸發 closePane
   172→    this.panes.delete(agentId);
   173→
   174→    try {
   175→      await this.controller.closePane(pane.id);
   176→    } catch {
   177→      // 靜默忽略關閉失敗（pane 可能已經關閉）
   178→    }
   179→  }
   180→
   181→  /**
   182→   * 目前開啟的 pane 數量
   183→   */
   184→  get activePaneCount(): number {
   185→    return this.panes.size;
   186→  }
   187→
   188→  /**
   189→   * 檢查指定 agentId 是否有對應的 pane（包含 pending 狀態）
   190→   * 用於判斷是否需要觸發 onSubagentDone
   191→   */
   192→  hasPaneForAgent(agentId: string): boolean {
   193→    return this.panes.has(agentId) || this.pendingAgentIds.has(agentId);
   194→  }
   195→}
