   412→  private clearScanTimer(): void {
   413→    if (this.scanTimer) {
   414→      clearTimeout(this.scanTimer);
   415→      this.scanTimer = null;
   416→    }
   417→  }
   418→
   419→  private scheduleScan(): void {
   420→    if (!this.isWatching) return;
   421→    this.clearScanTimer();
   422→    this.scanTimer = setTimeout(async () => {
   423→      if (!this.isWatching) return;
